/**
 * Cascades-local connected join-island planner.
 * <p>
 * This is deliberately not a wrapper around {@code JoinOrderPlanner}. It flattens a reorderable inner-join island into
 * factors, treats factor variables as a join hypergraph, and enumerates only connected left-deep prefixes. This gives
 * budgeted Cascades a complete non-Cartesian physical winner before the generic binary join rewrite rules can spend the
 * budget on commutation/association noise.
 * <p>
 * Property paths are handled as endpoint-dependent factors: an unbound path is not an admissible seed when another
 * factor can bind one of its endpoints, and a path is not appended until at least one endpoint is already bound. This
 * is the important distinction for AAS-style queries where {@code ?p1 aas:idShort "ratedPower"} must bind the path
 * object before {@code (aas:value)* ?p1} is evaluated.
 */
final class LmdbCascadesConnectedJoinPlanner {
	static final String ACCESS_PATH = "lmdbCascadesConnectedHypergraphJoin";
	static final String ESTIMATE_SOURCE = "lmdb-cascades-connected-hypergraph";
	static final String RULE_ID = "lmdb-cascades-connected-hypergraph-join";
	static final String CONNECTED_ENUMERATION = "connected-prefix-only";
	static final String RUNTIME_CONNECTED_WITH_ZERO_VAR_ENUMERATION = "runtime-connected-plus-zero-var-filters";
	private static final int EXACT_DP_FACTOR_LIMIT = 20;

	private LmdbCascadesConnectedJoinPlanner() {
	}

	static Optional<Plan> plan(TupleExpr joinIsland, Set<String> initialBoundVars, JoinFactorCostModel costModel,
			EvaluationStatistics fallbackStatistics) {
		if (joinIsland == null || costModel == null
				|| !LmdbJoinIslandConnectivity.connectedJoinProviderCanOwn(joinIsland)) {
			return Optional.empty();
		}
		LmdbEvaluationStatistics scopedStatistics = scopedPlanCacheStatistics(costModel, fallbackStatistics);
		List<TupleExpr> factors = canonicalFactors(LmdbJoinIslandConnectivity.flattenFactors(joinIsland),
				scopedStatistics);
		if (factors.size() < 2) {
			return Optional.empty();
		}
		boolean greedy = factors.size() > EXACT_DP_FACTOR_LIMIT;
		PlanCacheKey cacheKey = scopedPlanCacheAvailable(scopedStatistics)
				? new PlanCacheKey(factorFingerprints(factors, scopedStatistics), plannerNames(initialBoundVars),
						greedy)
				: null;
		Optional<PlanTemplate> cachedTemplate = cachedPlanTemplate(scopedStatistics, cacheKey);
		if (cachedTemplate != null) {
			return cachedTemplate.map(template -> template.toPlan(factors));
		}

		Optional<PlanTemplate> template = greedy
				? greedyPlan(factors, initialBoundVars, costModel, fallbackStatistics)
				: dpPlan(factors, initialBoundVars, costModel, fallbackStatistics);
		cachePlanTemplate(scopedStatistics, cacheKey, template);
		return template.map(planTemplate -> planTemplate.toPlan(factors));
	}

	private static Optional<PlanTemplate> dpPlan(List<TupleExpr> factors, Set<String> initialBoundVars,
			JoinFactorCostModel costModel, EvaluationStatistics fallbackStatistics) {
		int factorCount = factors.size();
		List<Set<String>> factorVars = factorVars(factors);
		List<Integer> runtimeFactorIndices = runtimeFactorIndices(factorVars);
		List<Integer> zeroVarFactorIndices = zeroVarFactorIndices(factorVars);
		if (runtimeFactorIndices.size() < 2) {
			return Optional.empty();
		}
		int fullMask = maskFor(runtimeFactorIndices);
		Set<String> initial = plannerNames(initialBoundVars);
		boolean[] pathHasEndpointBinder = pathHasEndpointBinder(factors, factorVars);
		State[] best = new State[1 << factorCount];

		for (int factorIndex : runtimeFactorIndices) {
			if (!admissibleSeed(factors.get(factorIndex), initial, pathHasEndpointBinder[factorIndex])) {
				continue;
			}
			Step step = estimateStep(factors, factorIndex, initial, 0.0d, false, List.of(), costModel,
					fallbackStatistics);
			if (step == null) {
				continue;
			}
			int mask = 1 << factorIndex;
			State state = State.seed(mask, factorIndex, step, union(initial, factorVars.get(factorIndex)));
			best[mask] = better(best[mask], state);
		}

		for (int mask = 1; mask <= fullMask; mask++) {
			State state = best[mask];
			if (state == null) {
				continue;
			}
			List<TupleExpr> prefixFactors = state.prefixFactors(factors);
			for (int factorIndex : runtimeFactorIndices) {
				int bit = 1 << factorIndex;
				if ((mask & bit) != 0 || !connectedExtension(factors.get(factorIndex), state.boundVars(),
						factorVars.get(factorIndex))) {
					continue;
				}
				Step step = estimateStep(factors, factorIndex, state.boundVars(), state.rows(), true,
						prefixFactors, costModel, fallbackStatistics);
				if (step == null) {
					continue;
				}
				State next = state.append(mask | bit, factorIndex, step,
						union(state.boundVars(), factorVars.get(factorIndex)));
				best[next.mask()] = better(best[next.mask()], next);
			}
		}

		State full = best[fullMask];
		if (full == null) {
			return Optional.empty();
		}
		State complete = appendZeroVarFactors(full, factors, zeroVarFactorIndices, costModel, fallbackStatistics);
		if (complete == null) {
			return Optional.empty();
		}
		return Optional.of(new PlanTemplate(complete, "connected-dp", zeroVarFactorIndices.size()));
	}

	private static Optional<PlanTemplate> greedyPlan(List<TupleExpr> factors, Set<String> initialBoundVars,
			JoinFactorCostModel costModel, EvaluationStatistics fallbackStatistics) {
		List<Set<String>> factorVars = factorVars(factors);
		List<Integer> remaining = new ArrayList<>(runtimeFactorIndices(factorVars));
		List<Integer> zeroVarFactorIndices = zeroVarFactorIndices(factorVars);
		if (remaining.size() < 2) {
			return Optional.empty();
		}
		boolean[] pathHasEndpointBinder = pathHasEndpointBinder(factors, factorVars);
		Set<String> boundVars = plannerNames(initialBoundVars);
		List<Integer> order = new ArrayList<>(factors.size());
		List<Step> steps = new ArrayList<>(factors.size());
		double rows = 0.0d;
		double workRows = 0.0d;
		double maxRows = 0.0d;
		while (!remaining.isEmpty()) {
			int selectedPosition = -1;
			Step selectedStep = null;
			List<TupleExpr> prefixFactors = prefixFactors(factors, order);
			for (int position = 0; position < remaining.size(); position++) {
				int factorIndex = remaining.get(position);
				TupleExpr factor = factors.get(factorIndex);
				boolean hasPrefix = !order.isEmpty();
				if (!hasPrefix && !admissibleSeed(factor, boundVars, pathHasEndpointBinder[factorIndex])) {
					continue;
				}
				if (hasPrefix && !connectedExtension(factor, boundVars, factorVars.get(factorIndex))) {
					continue;
				}
				Step step = estimateStep(factors, factorIndex, boundVars, rows, hasPrefix,
						prefixFactors, costModel, fallbackStatistics);
				if (step == null) {
					continue;
				}
				if (selectedStep == null || step.compareTo(selectedStep) < 0) {
					selectedStep = step;
					selectedPosition = position;
				}
			}
			if (selectedPosition < 0 || selectedStep == null) {
				return Optional.empty();
			}
			int factorIndex = remaining.remove(selectedPosition);
			order.add(factorIndex);
			steps.add(selectedStep);
			rows = selectedStep.outputRows();
			workRows += selectedStep.workRows();
			maxRows = Math.max(maxRows, rows);
			boundVars = union(boundVars, factorVars.get(factorIndex));
		}
		State state = new State(maskFor(order), List.copyOf(order), List.copyOf(steps),
				boundVars, rows, workRows, maxRows, 0.0d, qErrorMax(steps), workQErrorMax(steps), confidence(steps),
				evidence(steps));
		State complete = appendZeroVarFactors(state, factors, zeroVarFactorIndices, costModel, fallbackStatistics);
		if (complete == null) {
			return Optional.empty();
		}
		return Optional.of(new PlanTemplate(complete, "connected-greedy", zeroVarFactorIndices.size()));
	}

	private static List<TupleExpr> canonicalFactors(List<TupleExpr> factors, LmdbEvaluationStatistics statistics) {
		if (factors == null || factors.isEmpty()) {
			return List.of();
		}
		if (statistics == null) {
			return List.copyOf(factors);
		}
		List<TupleExpr> canonical = new ArrayList<>(factors);
		canonical.sort((left, right) -> compareFactors(left, right, statistics));
		return List.copyOf(canonical);
	}

	private static int compareFactors(TupleExpr left, TupleExpr right, LmdbEvaluationStatistics statistics) {
		if (left == right) {
			return 0;
		}
		if (left == null) {
			return -1;
		}
		if (right == null) {
			return 1;
		}
		Object leftFingerprint = factorFingerprint(left, statistics);
		Object rightFingerprint = factorFingerprint(right, statistics);
		int comparison = Integer.compare(nullableHash(leftFingerprint), nullableHash(rightFingerprint));
		if (comparison != 0) {
			return comparison;
		}
		comparison = className(leftFingerprint).compareTo(className(rightFingerprint));
		if (comparison != 0) {
			return comparison;
		}
		if (leftFingerprint == null ? rightFingerprint == null : leftFingerprint.equals(rightFingerprint)) {
			return 0;
		}
		// Rare hash/class collision: keep equivalent Cascades alternatives deterministic.
		return String.valueOf(leftFingerprint).compareTo(String.valueOf(rightFingerprint));
	}

	private static int nullableHash(Object value) {
		return value == null ? 0 : value.hashCode();
	}

	private static String className(Object value) {
		return value == null ? "" : value.getClass().getName();
	}

	private static List<Object> factorFingerprints(List<TupleExpr> factors, LmdbEvaluationStatistics statistics) {
		if (factors == null || factors.isEmpty()) {
			return List.of();
		}
		List<Object> fingerprints = new ArrayList<>(factors.size());
		for (TupleExpr factor : factors) {
			fingerprints.add(factorFingerprint(factor, statistics));
		}
		return List.copyOf(fingerprints);
	}

	private static Object factorFingerprint(TupleExpr factor, LmdbEvaluationStatistics statistics) {
		if (statistics != null) {
			return statistics.optimizationScopedFactorFingerprint(factor);
		}
		return factor == null ? null : factor;
	}

	@SuppressWarnings("unchecked")
	private static Optional<PlanTemplate> cachedPlanTemplate(LmdbEvaluationStatistics statistics,
			PlanCacheKey cacheKey) {
		if (statistics == null || cacheKey == null) {
			return null;
		}
		Object cached = statistics.getOptimizationScopedPlannerCacheValue(cacheKey);
		if (cached instanceof Optional<?>) {
			return (Optional<PlanTemplate>) cached;
		}
		return null;
	}

	private static void cachePlanTemplate(LmdbEvaluationStatistics statistics, PlanCacheKey cacheKey,
			Optional<PlanTemplate> template) {
		if (statistics != null && cacheKey != null && template != null) {
			statistics.putOptimizationScopedPlannerCacheValue(cacheKey, template);
		}
	}

	private static boolean scopedPlanCacheAvailable(LmdbEvaluationStatistics statistics) {
		return statistics != null && statistics.hasOptimizationScopedPlannerCache();
	}

	private static LmdbEvaluationStatistics scopedPlanCacheStatistics(JoinFactorCostModel costModel,
			EvaluationStatistics fallbackStatistics) {
		if (costModel instanceof LmdbEvaluationStatistics statistics) {
			return statistics;
		}
		if (fallbackStatistics instanceof LmdbEvaluationStatistics statistics) {
			return statistics;
		}
		return null;
	}

	private static Step estimateStep(List<TupleExpr> factors, int factorIndex, Set<String> boundVars, double prefixRows,
			boolean nested, List<TupleExpr> prefixFactors, JoinFactorCostModel costModel,
			EvaluationStatistics fallbackStatistics) {
		return estimateStep(factors, factorIndex, boundVars, prefixRows, nested, prefixFactors, costModel,
				fallbackStatistics, false);
	}

	private static Step estimateStep(List<TupleExpr> factors, int factorIndex, Set<String> boundVars, double prefixRows,
			boolean nested, List<TupleExpr> prefixFactors, JoinFactorCostModel costModel,
			EvaluationStatistics fallbackStatistics, boolean disconnected) {
		TupleExpr factor = factors.get(factorIndex);
		CostContext context = CostContext.forOptimization(boundVars, prefixRows,
				Double.isFinite(prefixRows) && prefixRows > 0.0d ? prefixRows : Double.NaN, nested, true, Map.of(),
				prefixFactors).withEstimationTier(EstimationTier.STANDARD);
		Optional<JoinFactorCostModel.FactorCostEstimate> estimate = costModel.estimateFactorCost(factor, context);
		JoinFactorCostModel.FactorCostEstimate factorEstimate = estimate
				.orElseGet(() -> fallbackEstimate(factor, fallbackStatistics));
		if (factorEstimate == null) {
			return null;
		}
		double outputRows = finiteNonNegative(factorEstimate.getOutputRows(), Double.MAX_VALUE);
		double workRows = finiteNonNegative(factorEstimate.getWorkRows(), outputRows);
		return new Step(factorIndex, plannerNames(boundVars), workRows, outputRows, factorEstimate.getStringMetrics(),
				factorEstimate.getDoubleMetrics(), factorEstimate.getEstimateVector().rowQErrorMax(),
				factorEstimate.getEstimateVector().workQErrorMax(), factorEstimate.getEstimateVector().confidence(),
				factorEstimate.getEstimateVector().evidenceCount(), disconnected);
	}

	private static JoinFactorCostModel.FactorCostEstimate fallbackEstimate(TupleExpr factor,
			EvaluationStatistics fallbackStatistics) {
		double rows = fallbackStatistics == null || factor == null ? Double.NaN
				: fallbackStatistics.getCardinality(factor);
		if (!Double.isFinite(rows) || rows < 0.0d) {
			rows = 1.0d;
		}
		Map<String, String> strings = Map.of(TelemetryMetricNames.PLANNED_ESTIMATE_SOURCE,
				"lmdb-cascades-connected-fallback");
		Map<String, Double> doubles = Map.of(TelemetryMetricNames.PLANNED_CARDINALITY_ROWS, rows,
				TelemetryMetricNames.PLANNED_WORK_ROWS, rows);
		return new JoinFactorCostModel.FactorCostEstimate(rows, rows, strings, doubles);
	}

	private static State better(State incumbent, State candidate) {
		if (incumbent == null) {
			return candidate;
		}
		return candidate.compareTo(incumbent) < 0 ? candidate : incumbent;
	}

	private static boolean admissibleSeed(TupleExpr factor, Set<String> initialBoundVars,
			boolean pathHasEndpointBinder) {
		if (!path(factor)) {
			return true;
		}
		return pathHasBoundEndpoint(factor, initialBoundVars) || !pathHasEndpointBinder;
	}

	private static boolean connectedExtension(TupleExpr candidate, Set<String> prefixVars, Set<String> candidateVars) {
		if (path(candidate)) {
			return pathHasBoundEndpoint(candidate, prefixVars);
		}
		if (candidateVars == null || candidateVars.isEmpty()) {
			return false;
		}
		return intersects(prefixVars, candidateVars);
	}

	private static boolean hasDisconnectedStep(State state) {
		for (Step step : state.steps()) {
			if (step.disconnected()) {
				return true;
			}
		}
		return false;
	}

	private static State appendZeroVarFactors(State state, List<TupleExpr> factors, List<Integer> zeroVarFactorIndices,
			JoinFactorCostModel costModel, EvaluationStatistics fallbackStatistics) {
		State current = state;
		for (int factorIndex : zeroVarFactorIndices) {
			Step step = estimateStep(factors, factorIndex, current.boundVars(), current.rows(), true,
					current.prefixFactors(factors), costModel, fallbackStatistics, true);
			if (step == null) {
				return null;
			}
			current = current.append(current.mask(), factorIndex, step, current.boundVars());
		}
		return current;
	}

	private static List<Integer> runtimeFactorIndices(List<Set<String>> factorVars) {
		List<Integer> indices = new ArrayList<>();
		for (int i = 0; i < factorVars.size(); i++) {
			if (!factorVars.get(i).isEmpty()) {
				indices.add(i);
			}
		}
		return List.copyOf(indices);
	}

	private static List<Integer> zeroVarFactorIndices(List<Set<String>> factorVars) {
		List<Integer> indices = new ArrayList<>();
		for (int i = 0; i < factorVars.size(); i++) {
			if (factorVars.get(i).isEmpty()) {
				indices.add(i);
			}
		}
		return List.copyOf(indices);
	}

	private static int maskFor(List<Integer> factorIndices) {
		int mask = 0;
		for (int factorIndex : factorIndices) {
			mask |= 1 << factorIndex;
		}
		return mask;
	}

	private static boolean[] pathHasEndpointBinder(List<TupleExpr> factors, List<Set<String>> factorVars) {
		boolean[] result = new boolean[factors.size()];
		for (int i = 0; i < factors.size(); i++) {
			TupleExpr factor = factors.get(i);
			if (!path(factor)) {
				continue;
			}
			Set<String> endpoints = pathEndpointNames(factor);
			for (int j = 0; j < factors.size(); j++) {
				if (i != j && intersects(endpoints, factorVars.get(j))) {
					result[i] = true;
					break;
				}
			}
		}
		return result;
	}

	private static List<Set<String>> factorVars(List<TupleExpr> factors) {
		List<Set<String>> factorVars = new ArrayList<>(factors.size());
		for (TupleExpr factor : factors) {
			factorVars.add(LmdbJoinPlanSupport.runtimeBindingNames(factor));
		}
		return List.copyOf(factorVars);
	}

	private static Set<String> plannerNames(Set<String> names) {
		if (names == null || names.isEmpty()) {
			return Set.of();
		}
		return LmdbJoinPlanSupport.plannerBindingNames(names);
	}

	private static boolean path(TupleExpr tupleExpr) {
		return tupleExpr instanceof ArbitraryLengthPath || tupleExpr instanceof ZeroLengthPath;
	}

	private static boolean pathHasBoundEndpoint(TupleExpr tupleExpr, Set<String> boundVars) {
		if (boundVars == null || boundVars.isEmpty()) {
			return false;
		}
		return intersects(pathEndpointNames(tupleExpr), plannerNames(boundVars));
	}

	private static Set<String> pathEndpointNames(TupleExpr tupleExpr) {
		if (tupleExpr instanceof ArbitraryLengthPath path) {
			return endpointNames(path.getSubjectVar(), path.getObjectVar());
		}
		if (tupleExpr instanceof ZeroLengthPath path) {
			return endpointNames(path.getSubjectVar(), path.getObjectVar());
		}
		return Set.of();
	}

	private static Set<String> endpointNames(Var left, Var right) {
		LinkedHashSet<String> names = new LinkedHashSet<>();
		addEndpointName(names, left);
		addEndpointName(names, right);
		return names.isEmpty() ? Set.of() : Set.copyOf(names);
	}

	private static void addEndpointName(Set<String> names, Var var) {
		if (var == null || var.hasValue() || var.isConstant()) {
			return;
		}
		String name = var.getName();
		if (name != null && !name.startsWith("_const_")) {
			names.add(name);
		}
	}

	private static List<TupleExpr> prefixFactors(List<TupleExpr> factors, List<Integer> order) {
		if (order == null || order.isEmpty()) {
			return List.of();
		}
		List<TupleExpr> prefix = new ArrayList<>(order.size());
		for (int factorIndex : order) {
			prefix.add(factors.get(factorIndex));
		}
		return List.copyOf(prefix);
	}

	private static Set<String> union(Set<String> left, Set<String> right) {
		if ((left == null || left.isEmpty()) && (right == null || right.isEmpty())) {
			return Set.of();
		}
		Set<String> union = new LinkedHashSet<>();
		if (left != null) {
			union.addAll(left);
		}
		if (right != null) {
			union.addAll(right);
		}
		return union.isEmpty() ? Set.of() : Set.copyOf(union);
	}

	private static boolean intersects(Set<String> left, Set<String> right) {
		if (left == null || left.isEmpty() || right == null || right.isEmpty()) {
			return false;
		}
		Set<String> smaller = left.size() <= right.size() ? left : right;
		Set<String> larger = left.size() <= right.size() ? right : left;
		for (String value : smaller) {
			if (larger.contains(value)) {
				return true;
			}
		}
		return false;
	}

	private static double finiteNonNegative(double value, double fallback) {
		return Double.isFinite(value) && value >= 0.0d ? value : fallback;
	}

	private static double qErrorMax(List<Step> steps) {
		double qError = 1.0d;
		for (Step step : steps) {
			qError = Math.max(qError, step.rowQErrorMax());
		}
		return qError;
	}

	private static double workQErrorMax(List<Step> steps) {
		double qError = 1.0d;
		for (Step step : steps) {
			qError = Math.max(qError, step.workQErrorMax());
		}
		return qError;
	}

	private static double confidence(List<Step> steps) {
		double confidence = 1.0d;
		for (Step step : steps) {
			confidence = Math.min(confidence, step.confidence());
		}
		return confidence;
	}

	private static double evidence(List<Step> steps) {
		double evidence = 0.0d;
		for (Step step : steps) {
			evidence += step.evidenceCount();
		}
		return evidence;
	}

	record Plan(TupleExpr tupleExpr, CostVector cost, EstimateSnapshot estimate, int factorCount, String algorithm,
			int zeroVarFactorCount) {
	}

	private record PlanTemplate(State state, String algorithm, int zeroVarFactorCount) {
		private Plan toPlan(List<TupleExpr> factors) {
			return state.toPlan(factors, algorithm, zeroVarFactorCount);
		}
	}

	private record PlanCacheKey(List<Object> factors, Set<String> initialBoundVars, boolean greedy) {
		private PlanCacheKey {
			factors = factors == null || factors.isEmpty() ? List.of() : List.copyOf(factors);
			initialBoundVars = initialBoundVars == null || initialBoundVars.isEmpty() ? Set.of()
					: Set.copyOf(initialBoundVars);
		}
	}

	private record State(int mask, List<Integer> order, List<Step> steps, Set<String> boundVars, double rows,
			double workRows, double maxRows, double cartesianWorkRows, double rowQErrorMax, double workQErrorMax,
			double confidence, double evidenceCount) implements Comparable<State> {

		static State seed(int mask, int factorIndex, Step step, Set<String> boundVars) {
			return new State(mask, List.of(factorIndex), List.of(step), boundVars, step.outputRows(), step.workRows(),
					step.outputRows(), 0.0d, step.rowQErrorMax(), step.workQErrorMax(), step.confidence(),
					step.evidenceCount());
		}

		State append(int mask, int factorIndex, Step step, Set<String> boundVars) {
			List<Integer> nextOrder = new ArrayList<>(order.size() + 1);
			nextOrder.addAll(order);
			nextOrder.add(factorIndex);
			List<Step> nextSteps = new ArrayList<>(steps.size() + 1);
			nextSteps.addAll(steps);
			nextSteps.add(step);
			double nextCartesianWorkRows = cartesianWorkRows + (step.disconnected() ? step.workRows() : 0.0d);
			return new State(mask, List.copyOf(nextOrder), List.copyOf(nextSteps), boundVars, step.outputRows(),
					workRows + step.workRows(), Math.max(maxRows, step.outputRows()), nextCartesianWorkRows,
					Math.max(rowQErrorMax, step.rowQErrorMax()), Math.max(workQErrorMax, step.workQErrorMax()),
					Math.min(confidence, step.confidence()), evidenceCount + step.evidenceCount());
		}

		List<TupleExpr> prefixFactors(List<TupleExpr> factors) {
			return LmdbCascadesConnectedJoinPlanner.prefixFactors(factors, order);
		}

		Plan toPlan(List<TupleExpr> factors, String algorithm, int zeroVarFactorCount) {
			TupleExpr tupleExpr = buildPlan(factors);
			CostVector cost = new CostVector(rows, workRows, 0.0d, 0.0d, 0.0d, rowQErrorMax, rowQErrorMax,
					workQErrorMax, workQErrorMax, Math.max(0.0d, rows * Math.max(rowQErrorMax - 1.0d, 0.0d)),
					confidence, evidenceCount);
			EstimateSnapshot estimate = estimateSnapshot(cost, algorithm, factors.size(), order.size(), maxRows,
					cartesianWorkRows, zeroVarFactorCount);
			return new Plan(tupleExpr, cost, estimate, factors.size(), algorithm, zeroVarFactorCount);
		}

		private TupleExpr buildPlan(List<TupleExpr> factors) {
			TupleExpr root = cloneFactor(factors.get(order.get(0)), steps.get(0));
			for (int i = 1; i < order.size(); i++) {
				Step step = steps.get(i);
				TupleExpr right = cloneFactor(factors.get(order.get(i)), step);
				Join join = new Join(root, right);
				stampPrefix(join, step, i + 1);
				root = join;
			}
			return root;
		}

		private TupleExpr cloneFactor(TupleExpr factor, Step step) {
			TupleExpr clone = factor.clone();
			if (step != null) {
				stampFactor(clone, step);
			}
			return clone;
		}

		private void stampFactor(TupleExpr tupleExpr, Step step) {
			for (Map.Entry<String, String> entry : step.stringMetrics().entrySet()) {
				if (!localRuntimeStringMetric(entry.getKey())) {
					tupleExpr.setStringMetricPlanned(entry.getKey(), entry.getValue());
				}
			}
			for (Map.Entry<String, Double> entry : step.doubleMetrics().entrySet()) {
				tupleExpr.setDoubleMetricPlanned(entry.getKey(), entry.getValue());
			}
			if (!step.boundVarsBefore().isEmpty()) {
				tupleExpr.setStringMetricPlanned(TelemetryMetricNames.PLANNED_BOUND_VARS,
						LmdbJoinPlanSupport.describeBindingNames(step.boundVarsBefore()));
			}
			tupleExpr.setStringMetricPlanned(TelemetryMetricNames.PLANNED_ESTIMATE_SOURCE, ESTIMATE_SOURCE);
			tupleExpr.setStringMetricPlanned(TelemetryMetricNames.PLANNED_ESTIMATE_USAGE,
					TelemetryMetricNames.PLANNED_ESTIMATE_USAGE_ALTERNATIVE_RANKING);
			tupleExpr.setDoubleMetricPlanned(TelemetryMetricNames.PLANNED_CARDINALITY_ROWS, step.outputRows());
			tupleExpr.setDoubleMetricPlanned(TelemetryMetricNames.PLANNED_WORK_ROWS, step.workRows());
			tupleExpr.setDoubleMetricPlanned(TelemetryMetricNames.PLANNED_COST_WORK_ROWS, step.workRows());
		}

		private void stampPrefix(Join join, Step step, int prefixFactorCount) {
			join.setStringMetricPlanned(TelemetryMetricNames.PLANNED_ESTIMATE_SOURCE, ESTIMATE_SOURCE);
			join.setStringMetricPlanned(TelemetryMetricNames.PLANNED_ESTIMATE_USAGE,
					TelemetryMetricNames.PLANNED_ESTIMATE_USAGE_ALTERNATIVE_RANKING);
			join.setStringMetricPlanned(TelemetryMetricNames.PLANNER_ALGORITHM, "CONNECTED_HYPERGRAPH_DP");
			join.setStringMetricPlanned("optimizer.connectedEnumeration",
					step.disconnected() ? RUNTIME_CONNECTED_WITH_ZERO_VAR_ENUMERATION : CONNECTED_ENUMERATION);
			join.setDoubleMetricPlanned("optimizer.connectedPrefixFactorCount", (double) prefixFactorCount);
			join.setDoubleMetricPlanned(TelemetryMetricNames.PLANNED_CARDINALITY_ROWS, step.outputRows());
			join.setDoubleMetricPlanned(TelemetryMetricNames.PLANNED_COST_FINAL_ROWS, step.outputRows());
			join.setDoubleMetricPlanned(TelemetryMetricNames.PLANNED_WORK_ROWS, cumulativeWorkThrough(step));
			join.setDoubleMetricPlanned(TelemetryMetricNames.PLANNED_COST_WORK_ROWS, cumulativeWorkThrough(step));
			join.setDoubleMetricPlanned(TelemetryMetricNames.PLANNED_COST_CARTESIAN_WORK_ROWS,
					cumulativeCartesianThrough(step));
		}

		private double cumulativeWorkThrough(Step step) {
			double work = 0.0d;
			for (Step current : steps) {
				work += current.workRows();
				if (current == step) {
					return work;
				}
			}
			return work;
		}

		private double cumulativeCartesianThrough(Step step) {
			double work = 0.0d;
			for (Step current : steps) {
				if (current.disconnected()) {
					work += current.workRows();
				}
				if (current == step) {
					return work;
				}
			}
			return work;
		}

		private EstimateSnapshot estimateSnapshot(CostVector cost, String algorithm, int factorCount,
				int acceptedStates,
				double maxRows, double cartesianWorkRows, int zeroVarFactorCount) {
			Map<String, String> strings = new LinkedHashMap<>();
			strings.put(TelemetryMetricNames.PLANNER_ID, "lmdb-cascades");
			strings.put(TelemetryMetricNames.PLANNED_ESTIMATE_SOURCE, ESTIMATE_SOURCE);
			strings.put(TelemetryMetricNames.PLANNED_ESTIMATE_USAGE,
					TelemetryMetricNames.PLANNED_ESTIMATE_USAGE_ALTERNATIVE_RANKING);
			strings.put(TelemetryMetricNames.PLANNER_ALGORITHM, "CONNECTED_HYPERGRAPH_DP");
			strings.put("optimizer.connectedEnumeration", zeroVarFactorCount == 0
					? CONNECTED_ENUMERATION
					: RUNTIME_CONNECTED_WITH_ZERO_VAR_ENUMERATION);
			strings.put("optimizer.hypergraphPlanner", algorithm);
			Map<String, Double> doubles = new LinkedHashMap<>();
			doubles.put("optimizer.connectedComponentCount", 1.0d + zeroVarFactorCount);
			doubles.put("optimizer.zeroVarFactorCount", (double) zeroVarFactorCount);
			doubles.put("optimizer.joinIslandFactorCount", (double) factorCount);
			doubles.put("optimizer.connectedDpStateCount", (double) acceptedStates);
			doubles.put(TelemetryMetricNames.PLANNED_COST_FINAL_ROWS, rows);
			doubles.put(TelemetryMetricNames.PLANNED_COST_MAX_INTERMEDIATE_ROWS, maxRows);
			doubles.put(TelemetryMetricNames.PLANNED_COST_CARTESIAN_WORK_ROWS, cartesianWorkRows);
			doubles.put(TelemetryMetricNames.PLANNED_OBJECTIVE_SCORE, cost.objectiveScore());
			return new EstimateSnapshot("lmdb-cascades", ESTIMATE_SOURCE,
					TelemetryMetricNames.PLANNED_ESTIMATE_USAGE_ALTERNATIVE_RANKING, rows, workRows, cost,
					Collections.unmodifiableMap(strings), Collections.unmodifiableMap(doubles));
		}

		private boolean localRuntimeStringMetric(String key) {
			return TelemetryMetricNames.PLANNER_ID.equals(key)
					|| TelemetryMetricNames.PLANNED_ESTIMATE_SOURCE.equals(key)
					|| TelemetryMetricNames.PLANNED_ESTIMATE_USAGE.equals(key)
					|| TelemetryMetricNames.PLANNED_ESTIMATE_DECISION_ID.equals(key)
					|| TelemetryMetricNames.PLANNED_CARDINALITY_SHAPE.equals(key)
					|| TelemetryMetricNames.PLANNED_COST_SHAPE.equals(key);
		}

		@Override
		public int compareTo(State other) {
			int comparison = Double.compare(workRows, other.workRows);
			if (comparison != 0) {
				return comparison;
			}
			comparison = Double.compare(rows, other.rows);
			if (comparison != 0) {
				return comparison;
			}
			comparison = Double.compare(maxRows, other.maxRows);
			if (comparison != 0) {
				return comparison;
			}
			return compareOrder(order, other.order);
		}

		private int compareOrder(List<Integer> left, List<Integer> right) {
			int leftSize = left == null ? 0 : left.size();
			int rightSize = right == null ? 0 : right.size();
			int limit = Math.min(leftSize, rightSize);
			for (int i = 0; i < limit; i++) {
				int comparison = Integer.compare(left.get(i), right.get(i));
				if (comparison != 0) {
					return comparison;
				}
			}
			return Integer.compare(leftSize, rightSize);
		}
	}

	private record Step(int factorIndex, Set<String> boundVarsBefore, double workRows, double outputRows,
			Map<String, String> stringMetrics, Map<String, Double> doubleMetrics, double rowQErrorMax,
			double workQErrorMax, double confidence, double evidenceCount, boolean disconnected)
			implements Comparable<Step> {

		private Step {
			boundVarsBefore = boundVarsBefore == null || boundVarsBefore.isEmpty() ? Set.of()
					: Set.copyOf(boundVarsBefore);
			stringMetrics = stringMetrics == null || stringMetrics.isEmpty() ? Map.of() : Map.copyOf(stringMetrics);
			doubleMetrics = doubleMetrics == null || doubleMetrics.isEmpty() ? Map.of() : Map.copyOf(doubleMetrics);
			rowQErrorMax = Double.isFinite(rowQErrorMax) && rowQErrorMax >= 1.0d ? rowQErrorMax : 4.0d;
			workQErrorMax = Double.isFinite(workQErrorMax) && workQErrorMax >= 1.0d ? workQErrorMax : rowQErrorMax;
			confidence = Double.isFinite(confidence) ? Math.max(0.0d, Math.min(1.0d, confidence)) : 0.0d;
			evidenceCount = finiteNonNegative(evidenceCount, 0.0d);
		}

		@Override
		public int compareTo(Step other) {
			int comparison = Boolean.compare(disconnected, other.disconnected);
			if (comparison != 0) {
				return comparison;
			}
			comparison = Double.compare(workRows, other.workRows);
			if (comparison != 0) {
				return comparison;
			}
			comparison = Double.compare(outputRows, other.outputRows);
			if (comparison != 0) {
				return comparison;
			}
			return Integer.compare(factorIndex, other.factorIndex);
		}
	}
}
